1602	// dispatchInbound handles one already-decoded inbound frame on the resolved peer's view (ps):
1603	// it routes to that peer's resequencer / FEC decoder / reflector. The source demux in
1604	// demuxInbound has already selected ps so a shared socket serving many peers resequences each
1605	// peer's stream against that peer's own buffer; on the single-peer edge/hub ps.peer is the
1606	// embedded primary, so this is byte-identical to the pre-split singleton. raw is retained for
1607	// the probe transport (HandleEcho / Reflect re-decode it under the peer's psk).
1608	func (m *Multipath) dispatchInbound(ps *peerPathState, fr frame.Frame, raw []byte, srcAP netip.AddrPort) {
1609		pr := ps.peer
1610		switch f := fr.(type) {
1611		case frame.Data:
1612			// Decode already returned a fresh copy of the payload (it aliases nothing
1613			// else), so the resequencer may take ownership of it directly.
1614			rq := pr.resequencer.Load()
1615			if rq == nil {
1616				// The peer's heavy receive state is absent — not yet instantiated, or torn down on
1617				// session/liveness loss while a DATA frame was in flight on this readLoop. Drop it;
1618				// a fresh authenticated PROBE re-instantiates the ring before the next DATA lands.
1619				return
1620			}
1621			if fr := pr.fecRecv.Load(); fr != nil {
1622				// FEC on (T24): offer the data shard to the decoder BEFORE resequencing so a
1623				// later parity frame can reconstruct any group-mate lost in transit, then
1624				// deliver THIS received frame in its own right (the decoder never echoes a
1625				// directly-received data shard back). The shard's coded bytes are
1626				// OuterSeq || Payload — the same bytes the sender coded parity over.
1627				shard := fec.DataShard{Group: fec.GroupID(f.FECGroup), Index: int(f.FECIndex), Payload: fecShardPayload(f.OuterSeq, f.Payload)}
1628				recovered, _ := fr.offer(shard)
1629				rq.Observe(f.OuterSeq, f.Payload, srcAP)
1630				// Residual-loss accounting (T29): this outer-seq was natively delivered, so mark
1631				// it present in the post-recovery loss estimator. A seq never marked here nor via
1632				// a reconstruction below is loss that FEC did not mask.
1633				if fr.connLoss != nil {
1634					fr.connLoss.Observe(f.OuterSeq)
1635				}
1636				m.observeRecovered(fr, rq, recovered, srcAP)
1637			} else {
1638				rq.Observe(f.OuterSeq, f.Payload, srcAP)
1639			}
1640		case frame.Parity:
1641			// PARITY feeds the FEC decoder (T24); a group that has now accumulated enough
1642			// shards reconstructs its missing data frames, each resequenced at its ORIGINAL
1643			// outer-seq (carried in the recovered shard's coded bytes) so recovery composes
1644			// with T18 exactly like a natively-received frame. With FEC off, PARITY is
1645			// dropped (the pre-T24 behaviour).
1646			if fr := pr.fecRecv.Load(); fr != nil {
