		}
		clk.advance(testProbeInterval - testProbeRTT)
	}
	if pp.prober.State() != telemetry.StateUp {
		t.Fatalf("path %q not Up after %d successes: %v", pp.name, testProbeUpSucc, pp.prober.State())
	}
